import React, { useEffect, useState, useCallback } from 'react';
import { Member } from '../types';
import api from '../utils/api';
import { useLocation } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import Toast from '../components/Toast';

const TC: any = { student:'#3b82f6', staff:'#8b5cf6' };
const SC: any = { active:'#10b981', suspended:'#ef4444', pending:'#f59e0b' };

export default function Members() {
  const { user } = useAuth();
  const isLibrarian = user?.role === 'librarian';
  const [members, setMembers] = useState<Member[]>([]);
  const [total, setTotal]     = useState(0);
  const [page, setPage]       = useState(1);
  const [search, setSearch]   = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [typeFilter, setTypeFilter]     = useState('');
  const [loading, setLoading] = useState(true);
  const [modal, setModal]     = useState<Member | null>(null);
  const [toast, setToast]     = useState<any>(null);
  const location = useLocation();

  useEffect(() => {
    const s = new URLSearchParams(location.search).get('status');
    if (s) setStatusFilter(s);
  }, [location.search]);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get('/members', { params: { search, status: statusFilter, type: typeFilter, page, limit: 10 } });
      setMembers(data.data); setTotal(data.total);
    } finally { setLoading(false); }
  }, [search, statusFilter, typeFilter, page]);

  useEffect(() => { load(); }, [load]);

  const updateStatus = async (id: number, status: string, name: string) => {
    try {
      await api.put(`/members/${id}/status`, { status });
      setToast({ message: status==='active' ? `${name} approved!` : `${name} ${status}`, type:'success' });
      load();
    } catch { setToast({ message:'Failed to update', type:'error' }); }
  };

  const deleteMember = async (id: number, name: string) => {
    if (!window.confirm(`Delete "${name}"?`)) return;
    try { await api.delete(`/members/${id}`); setToast({ message:`${name} deleted`, type:'success' }); load(); }
    catch { setToast({ message:'Failed to delete', type:'error' }); }
  };

  return (
    <div className="page-enter" style={{ padding:'32px 36px', width:'100%' }}>
      {toast && <Toast message={toast.message} type={toast.type} onClose={()=>setToast(null)} />}

      <div style={{ marginBottom:28 }}>
        <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:32, fontWeight:700, color:'var(--text)' }}>Members</h1>
        <p style={{ color:'var(--text-muted)', fontSize:14, marginTop:4 }}>{total} registered members</p>
      </div>

      {/* Filters */}
      <div style={{ display:'flex', gap:12, marginBottom:20, flexWrap:'wrap' }}>
        <input className="field" style={{ flex:1, minWidth:220 }} value={search}
          onChange={e=>{setSearch(e.target.value);setPage(1);}} placeholder="Search name, email, ID..." />
        <select className="field" style={{ width:150 }} value={typeFilter} onChange={e=>{setTypeFilter(e.target.value);setPage(1);}}>
          <option value="">All Types</option>
          <option value="student">Student</option>
          <option value="staff">Staff</option>
        </select>
        <select className="field" style={{ width:160 }} value={statusFilter} onChange={e=>{setStatusFilter(e.target.value);setPage(1);}}>
          <option value="">All Status</option>
          <option value="pending">Pending</option>
          <option value="active">Active</option>
          <option value="suspended">Suspended</option>
        </select>
      </div>

      {/* Table */}
      <div style={{ background:'var(--bg2)', border:'1px solid var(--border)', borderRadius:16, overflow:'hidden' }}>
        <table className="tbl">
          <thead>
            <tr>{['ID','Name','Type','Department','Batch','Mobile','Status','Actions'].map(h=>(
              <th key={h}>{h}</th>
            ))}</tr>
          </thead>
          <tbody>
            {loading ? (
              <tr><td colSpan={8} style={{ textAlign:'center', padding:60 }}>
                <div style={{ width:28,height:28,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite',margin:'0 auto' }}/>
              </td></tr>
            ) : members.length ? members.map(m=>(
              <tr key={m.id}>
                <td style={{ fontSize:12, fontFamily:'monospace', fontWeight:700, color:'#c9a84c' }}>{m.member_id}</td>
                <td>
                  <div style={{ display:'flex', alignItems:'center', gap:10 }}>
                    <div style={{ width:34,height:34,background:'linear-gradient(135deg,#c9a84c,#8a6820)',borderRadius:'50%',display:'flex',alignItems:'center',justifyContent:'center',fontWeight:800,color:'#1a1a2e',fontSize:13,flexShrink:0 }}>
                      {m.name.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <div style={{ fontSize:14, fontWeight:700, color:'var(--text)' }}>{m.name}</div>
                      <div style={{ fontSize:12, color:'var(--text-muted)' }}>{m.email.toLowerCase()}</div>
                    </div>
                  </div>
                </td>
                <td>
                  <span style={{ fontSize:11,fontWeight:700,padding:'3px 10px',borderRadius:99,background:(TC[m.account_type]||'#6b7280')+'22',color:TC[m.account_type]||'#6b7280',textTransform:'capitalize' }}>
                    {m.account_type}
                  </span>
                </td>
                <td style={{ color:'var(--text-dim)', fontSize:13 }}>{m.department||'—'}</td>
                <td style={{ color:'var(--text-dim)', fontSize:13 }}>{m.batch||'—'}</td>
                <td style={{ color:'var(--text-dim)', fontSize:13 }}>{m.mobile||'—'}</td>
                <td>
                  <span style={{ fontSize:11,fontWeight:700,padding:'4px 11px',borderRadius:99,background:(SC[m.status]||'#6b7280')+'22',color:SC[m.status]||'#6b7280',textTransform:'capitalize' }}>
                    {m.status}
                  </span>
                </td>
                <td>
                  <div style={{ display:'flex', gap:5, flexWrap:'wrap' }}>
                    {m.status==='pending' && <button onClick={()=>updateStatus(m.id,'active',m.name)} style={{ padding:'5px 10px',background:'rgba(16,185,129,0.15)',color:'#10b981',border:'1px solid rgba(16,185,129,0.25)',borderRadius:7,fontSize:11,fontWeight:700,cursor:'pointer' }}>Approve</button>}
                    {m.status==='active' && <button onClick={()=>updateStatus(m.id,'suspended',m.name)} style={{ padding:'5px 10px',background:'rgba(239,68,68,0.12)',color:'#ef4444',border:'1px solid rgba(239,68,68,0.2)',borderRadius:7,fontSize:11,fontWeight:600,cursor:'pointer' }}>Suspend</button>}
                    {m.status==='suspended' && <button onClick={()=>updateStatus(m.id,'active',m.name)} style={{ padding:'5px 10px',background:'rgba(16,185,129,0.12)',color:'#10b981',border:'1px solid rgba(16,185,129,0.2)',borderRadius:7,fontSize:11,fontWeight:600,cursor:'pointer' }}>Activate</button>}
                    <button onClick={()=>setModal(m)} style={{ padding:'5px 10px',background:'var(--bg3)',color:'var(--text-dim)',border:'1px solid var(--border)',borderRadius:7,fontSize:11,cursor:'pointer' }}>View</button>
                    {isLibrarian && <button onClick={()=>deleteMember(m.id,m.name)} style={{ padding:'5px 10px',background:'rgba(239,68,68,0.1)',color:'#ef4444',border:'1px solid rgba(239,68,68,0.15)',borderRadius:7,fontSize:11,cursor:'pointer' }}>Delete</button>}
                  </div>
                </td>
              </tr>
            )) : (
              <tr><td colSpan={8} style={{ textAlign:'center',padding:60,color:'var(--text-muted)',fontSize:14,fontStyle:'italic' }}>No members found</td></tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {Math.ceil(total/10)>1 && (
        <div style={{ display:'flex',alignItems:'center',justifyContent:'center',gap:10,marginTop:20 }}>
          <button onClick={()=>setPage(p=>Math.max(1,p-1))} disabled={page===1} className="btn-ghost" style={{ opacity:page===1?0.4:1 }}>← Prev</button>
          <span style={{ fontSize:13,color:'var(--text-muted)' }}>Page {page} of {Math.ceil(total/10)}</span>
          <button onClick={()=>setPage(p=>Math.min(Math.ceil(total/10),p+1))} disabled={page===Math.ceil(total/10)} className="btn-ghost" style={{ opacity:page===Math.ceil(total/10)?0.4:1 }}>Next →</button>
        </div>
      )}

      {/* View Modal */}
      {modal && (
        <div style={{ position:'fixed',inset:0,background:'rgba(0,0,0,0.75)',backdropFilter:'blur(6px)',zIndex:1000,display:'flex',alignItems:'center',justifyContent:'center',padding:20 }}>
          <div style={{ background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:20,padding:28,width:'100%',maxWidth:460 }}>
            <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:20 }}>
              <h2 style={{ fontFamily:"'Playfair Display',serif",fontSize:20,fontWeight:700,color:'var(--text)' }}>Member Details</h2>
              <button onClick={()=>setModal(null)} style={{ background:'var(--bg3)',border:'1px solid var(--border)',color:'var(--text-dim)',width:32,height:32,borderRadius:8,cursor:'pointer',fontSize:16 }}>✕</button>
            </div>
            <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:10 }}>
              {[['Member ID',modal.member_id],['Account Type',modal.account_type],['Full Name',modal.name],['Email',modal.email],['Department',modal.department||'—'],['Batch',modal.batch||'—'],['Mobile',modal.mobile||'—'],['Gender',modal.gender||'—'],['Status',modal.status]].map(([label,value])=>(
                <div key={label} style={{ background:'var(--bg3)',border:'1px solid var(--border)',borderRadius:10,padding:'11px 13px' }}>
                  <div style={{ fontSize:10,fontWeight:700,color:'var(--text-muted)',marginBottom:4,textTransform:'uppercase',letterSpacing:'1px' }}>{label}</div>
                  <div style={{ fontSize:13,fontWeight:600,color:'var(--text)' }}>{value}</div>
                </div>
              ))}
              {modal.address && (
                <div style={{ gridColumn:'1/-1',background:'var(--bg3)',border:'1px solid var(--border)',borderRadius:10,padding:'11px 13px' }}>
                  <div style={{ fontSize:10,fontWeight:700,color:'var(--text-muted)',marginBottom:4,textTransform:'uppercase',letterSpacing:'1px' }}>Address</div>
                  <div style={{ fontSize:13,color:'var(--text)' }}>{modal.address}</div>
                </div>
              )}
            </div>
            {modal.status==='pending' && (
              <button onClick={()=>{updateStatus(modal.id,'active',modal.name);setModal(null);}} className="btn-primary" style={{ width:'100%',marginTop:16,padding:13 }}>
                Approve This Member
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
